import React from "react";
import { Routes, Route, NavLink, useNavigate } from "react-router-dom";
import "./AdminDashboard.css";

const AdminDashboard = () => {
  const navigate = useNavigate();

  const logout = () => {
    localStorage.removeItem("adminToken");
    navigate("/admin/login");
  };

  return (
    <div className="admin-layout">
      {/* SIDEBAR */}
      <aside className="admin-sidebar">
        <h2 className="logo">ShopAdmin</h2>

        <nav>
          <NavLink to="products" className="nav-link">
            Products
          </NavLink>
          <NavLink to="orders" className="nav-link">
            Orders
          </NavLink>
          <NavLink to="users" className="nav-link">
            Users
          </NavLink>
        </nav>

        <button className="logout-btn" onClick={logout}>
          Logout
        </button>
      </aside>

      {/* MAIN CONTENT */}
      <main className="admin-content">
        <header className="admin-header">
          <h1>Dashboard</h1>
        </header>

        <section className="admin-page">
          <Routes>
            <Route path="products" element={<h3>Manage Products</h3>} />
            <Route path="orders" element={<h3>Manage Orders</h3>} />
            <Route path="users" element={<h3>Manage Users</h3>} />
            <Route
              index
              element={<p>Welcome to your admin dashboard</p>}
            />
          </Routes>
        </section>
      </main>
    </div>
  );
};

export default AdminDashboard;
